            public Chromosome next() {
                lastReturned = snapshot.next();
                return lastReturned;
            }
            public void remove() {
                if (lastReturned == null) {
                    throw new IllegalStateException();
                }
                chromosomes.remove(lastReturned);
                lastReturned = null;
            }
        };
